CREATE DATABASE mi_api_db;
GO
USE mi_api_db;
GO

CREATE TABLE auditoria_usuarios (
  id INT IDENTITY(1,1) NOT NULL,
  usuario_id int NOT NULL,
  admin_id int DEFAULT NULL,
  accion varchar(50) NOT NULL,
  payload_anterior NVARCHAR(MAX) DEFAULT NULL,
  payload_nuevo NVARCHAR(MAX) DEFAULT NULL,
  fecha DATETIME2 DEFAULT GETDATE(),
  PRIMARY KEY (id),
  CONSTRAINT auditoria_usuarios_ibfk_1 FOREIGN KEY (usuario_id) REFERENCES usuarios (id),
  CONSTRAINT auditoria_usuarios_ibfk_2 FOREIGN KEY (admin_id) REFERENCES usuarios (id)
);
GO

CREATE TABLE distribuidoras (
  id BIGINT IDENTITY(1,1) NOT NULL,
  marca_id int NOT NULL,
  id_dist varchar(20) DEFAULT NULL,
  nombre varchar(255) DEFAULT NULL,
  url varchar(255) DEFAULT NULL,
  activa tinyINT DEFAULT '1',
  fecha_registro DATETIME2 DEFAULT GETDATE(),
  PRIMARY KEY (id),
  UNIQUE (id),
  UNIQUE (marca_id,id_dist),
  CONSTRAINT distribuidoras_ibfk_1 FOREIGN KEY (marca_id) REFERENCES marcas (id)
);
GO

CREATE TABLE ips_autorizadas (
  id INT IDENTITY(1,1) NOT NULL,
  marca varchar(100) NOT NULL,
  ip varchar(45) NOT NULL,
  PRIMARY KEY (id),
  UNIQUE (marca)
);
GO

CREATE TABLE logs_scraping (
  id BIGINT IDENTITY(1,1) NOT NULL,
  marca_id int NOT NULL,
  tipo varchar(50) NOT NULL,
  mensaje NVARCHAR(MAX),
  intento int NOT NULL,
  exitoso tinyINT NOT NULL,
  fecha DATETIME2 DEFAULT GETDATE(),
  PRIMARY KEY (id),
  UNIQUE (id),
  CONSTRAINT logs_scraping_ibfk_1 FOREIGN KEY (marca_id) REFERENCES marcas (id)
);
GO

CREATE TABLE marcas (
  id int NOT NULL,
  nombre varchar(255) NOT NULL,
  activa tinyINT DEFAULT '1',
  ultima_actualizacion DATETIME2 DEFAULT NULL,
  PRIMARY KEY (id)
);
GO

CREATE TABLE registros (
  id INT IDENTITY(1,1) NOT NULL,
  usuario_id int DEFAULT NULL,
  marca varchar(100) DEFAULT NULL,
  distribuidora varchar(255) DEFAULT NULL,
  action varchar(100) DEFAULT NULL,
  payload NVARCHAR(MAX) DEFAULT NULL,
  created_at DATETIME2 DEFAULT GETDATE(),
  PRIMARY KEY (id),
  CONSTRAINT registros_ibfk_1 FOREIGN KEY (usuario_id) REFERENCES usuarios (id)
);
GO

CREATE TABLE reportes (
  id INT IDENTITY(1,1) NOT NULL,
  usuario_id int NOT NULL,
  marca varchar(100) NOT NULL,
  distribuidoras NVARCHAR(MAX) NOT NULL,
  archivo_url varchar(255) NOT NULL,
  creado_en DATETIME2 DEFAULT GETDATE(),
  PRIMARY KEY (id),
  CONSTRAINT reportes_ibfk_1 FOREIGN KEY (usuario_id) REFERENCES usuarios (id)
);
GO

CREATE TABLE roles (
  id INT IDENTITY(1,1) NOT NULL,
  name varchar(50) NOT NULL,
  description NVARCHAR(MAX),
  PRIMARY KEY (id),
  UNIQUE (name)
);
GO

CREATE TABLE usuarios (
  id INT IDENTITY(1,1) NOT NULL,
  username varchar(100) NOT NULL,
  email varchar(150) NOT NULL,
  password_hash varchar(255) NOT NULL,
  role_id int DEFAULT NULL,
  created_at DATETIME2 DEFAULT GETDATE(),
  updated_at DATETIME2 DEFAULT GETDATE(),
  activo tinyINT DEFAULT '1',
  PRIMARY KEY (id),
  UNIQUE (email),
  CONSTRAINT usuarios_ibfk_1 FOREIGN KEY (role_id) REFERENCES roles (id)
);
GO

SET IDENTITY_INSERT distribuidoras ON;
GO
